import argparse
import importlib
import json
import os
import sys
import tempfile
from dataclasses import dataclass
from urllib.parse import urlparse

import torch
import torch.nn as nn
from torch.utils.data import DataLoader, Dataset, random_split
from torchvision import models, transforms
from torchvision.datasets import ImageFolder


@dataclass
class Config:
    model_name: str
    checkpoint_url: str
    data_dir: str
    output_dir: str
    batch_size: int
    epochs: int
    lr: float
    num_workers: int
    val_split: float
    device: str
    image_size: int
    freeze_backbone: bool


def get_device(device: str) -> torch.device:
    if device == "auto":
        return torch.device("cuda" if torch.cuda.is_available() else "cpu")
    return torch.device(device)


def safe_torch_load(url_or_path: str, map_location="cpu"):
    return torch.load(url_or_path, map_location=map_location)


def download_to_temp(url: str) -> str:
    import urllib.request

    suffix = os.path.basename(urlparse(url).path) or "checkpoint.pt"
    fd, path = tempfile.mkstemp(suffix=f"_{suffix}")
    os.close(fd)
    urllib.request.urlretrieve(url, path)
    return path


def load_checkpoint_from_url(url: str, map_location="cpu"):
    local_path = download_to_temp(url)
    try:
        return safe_torch_load(local_path, map_location=map_location)
    finally:
        try:
            os.remove(local_path)
        except OSError:
            pass


def build_model(model_name: str, num_classes: int):
    if not hasattr(models, model_name):
        raise ValueError(f"Unsupported model_name: {model_name}")
    model_fn = getattr(models, model_name)
    try:
        model = model_fn(weights=None)
    except TypeError:
        model = model_fn(pretrained=False)

    if hasattr(model, "fc") and isinstance(model.fc, nn.Module):
        in_features = model.fc.in_features
        model.fc = nn.Linear(in_features, num_classes)
        return model, "fc"

    if hasattr(model, "classifier"):
        classifier = model.classifier
        if isinstance(classifier, nn.Linear):
            in_features = classifier.in_features
            model.classifier = nn.Linear(in_features, num_classes)
            return model, "classifier"
        if isinstance(classifier, nn.Sequential):
            last_linear_idx = None
            in_features = None
            for idx in reversed(range(len(classifier))):
                if isinstance(classifier[idx], nn.Linear):
                    last_linear_idx = idx
                    in_features = classifier[idx].in_features
                    break
            if last_linear_idx is None:
                raise ValueError("Could not identify final linear layer in classifier.")
            new_classifier = list(classifier.children())
            new_classifier[last_linear_idx] = nn.Linear(in_features, num_classes)
            model.classifier = nn.Sequential(*new_classifier)
            return model, "classifier"
    raise ValueError("Unsupported architecture for automatic head replacement.")


def freeze_backbone(model: nn.Module, head_attr: str):
    for name, param in model.named_parameters():
        param.requires_grad = False
    if head_attr == "fc":
        for param in model.fc.parameters():
            param.requires_grad = True
    elif head_attr == "classifier":
        for param in model.classifier.parameters():
            param.requires_grad = True


def get_transforms(image_size: int):
    train_tfms = transforms.Compose(
        [
            transforms.RandomResizedCrop(image_size),
            transforms.RandomHorizontalFlip(),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
        ]
    )
    val_tfms = transforms.Compose(
        [
            transforms.Resize(image_size + 32),
            transforms.CenterCrop(image_size),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
        ]
    )
    return train_tfms, val_tfms


def split_dataset(dataset: Dataset, val_split: float):
    val_len = int(len(dataset) * val_split)
    train_len = len(dataset) - val_len
    return random_split(dataset, [train_len, val_len], generator=torch.Generator().manual_seed(42))


def make_dataloaders(data_dir: str, batch_size: int, num_workers: int, image_size: int, val_split: float):
    train_tfms, val_tfms = get_transforms(image_size)

    full_dataset = ImageFolder(root=data_dir, transform=train_tfms)
    train_set, val_set = split_dataset(full_dataset, val_split)

    val_set.dataset = ImageFolder(root=data_dir, transform=val_tfms)

    train_loader = DataLoader(train_set, batch_size=batch_size, shuffle=True, num_workers=num_workers, pin_memory=True)
    val_loader = DataLoader(val_set, batch_size=batch_size, shuffle=False, num_workers=num_workers, pin_memory=True)

    return train_loader, val_loader, full_dataset.classes


def train_one_epoch(model, loader, criterion, optimizer, device):
    model.train()
    running_loss = 0.0
    correct = 0
    total = 0

    for inputs, targets in loader:
        inputs = inputs.to(device)
        targets = targets.to(device)

        optimizer.zero_grad(set_to_none=True)
        outputs = model(inputs)
        loss = criterion(outputs, targets)
        loss.backward()
        optimizer.step()

        running_loss += loss.item() * inputs.size(0)
        _, preds = outputs.max(1)
        correct += (preds == targets).sum().item()
        total += targets.size(0)

    return running_loss / max(total, 1), correct / max(total, 1)


@torch.no_grad()
def evaluate(model, loader, criterion, device):
    model.eval()
    running_loss = 0.0
    correct = 0
    total = 0

    for inputs, targets in loader:
        inputs = inputs.to(device)
        targets = targets.to(device)

        outputs = model(inputs)
        loss = criterion(outputs, targets)

        running_loss += loss.item() * inputs.size(0)
        _, preds = outputs.max(1)
        correct += (preds == targets).sum().item()
        total += targets.size(0)

    return running_loss / max(total, 1), correct / max(total, 1)


def save_artifacts(output_dir: str, model: nn.Module, classes, config: Config):
    os.makedirs(output_dir, exist_ok=True)
    torch.save(model.state_dict(), os.path.join(output_dir, "fine_tuned_model_state_dict.pt"))
    with open(os.path.join(output_dir, "classes.json"), "w", encoding="utf-8") as f:
        json.dump(classes, f)
    with open(os.path.join(output_dir, "config.json"), "w", encoding="utf-8") as f:
        json.dump(config.__dict__, f, indent=2)


def main():
    parser = argparse.ArgumentParser(description="Download pretrained models and fine-tune on custom datasets.")
    parser.add_argument("--model-name", type=str, default="resnet18")
    parser.add_argument("--checkpoint-url", type=str, default="")
    parser.add_argument("--data-dir", type=str, required=True)
    parser.add_argument("--output-dir", type=str, default="./output")
    parser.add_argument("--batch-size", type=int, default=32)
    parser.add_argument("--epochs", type=int, default=5)
    parser.add_argument("--lr", type=float, default=1e-3)
    parser.add_argument("--num-workers", type=int, default=4)
    parser.add_argument("--val-split", type=float, default=0.2)
    parser.add_argument("--device", type=str, default="auto")
    parser.add_argument("--image-size", type=int, default=224)
    parser.add_argument("--freeze-backbone", action="store_true")
    args = parser.parse_args()

    config = Config(
        model_name=args.model_name,
        checkpoint_url=args.checkpoint_url,
        data_dir=args.data_dir,
        output_dir=args.output_dir,
        batch_size=args.batch_size,
        epochs=args.epochs,
        lr=args.lr,
        num_workers=args.num_workers,
        val_split=args.val_split,
        device=args.device,
        image_size=args.image_size,
        freeze_backbone=args.freeze_backbone,
    )

    device = get_device(config.device)
    train_loader, val_loader, classes = make_dataloaders(
        config.data_dir,
        config.batch_size,
        config.num_workers,
        config.image_size,
        config.val_split,
    )

    model, head_attr = build_model(config.model_name, num_classes=len(classes))

    if config.checkpoint_url:
        ckpt = load_checkpoint_from_url(config.checkpoint_url, map_location="cpu")
        state_dict = ckpt.get("state_dict", ckpt.get("model_state_dict", ckpt))
        missing, unexpected = model.load_state_dict(state_dict, strict=False)
        print(f"Loaded checkpoint from URL. Missing keys: {len(missing)} | Unexpected keys: {len(unexpected)}")

    if config.freeze_backbone:
        freeze_backbone(model, head_attr)

    model = model.to(device)

    criterion = nn.CrossEntropyLoss()
    optimizer = torch.optim.AdamW((p for p in model.parameters() if p.requires_grad), lr=config.lr)

    best_val_acc = 0.0
    for epoch in range(config.epochs):
        train_loss, train_acc = train_one_epoch(model, train_loader, criterion, optimizer, device)
        val_loss, val_acc = evaluate(model, val_loader, criterion, device)
        print(
            f"Epoch {epoch+1}/{config.epochs} | "
            f"train_loss={train_loss:.4f} train_acc={train_acc:.4f} | "
            f"val_loss={val_loss:.4f} val_acc={val_acc:.4f}"
        )
        if val_acc > best_val_acc:
            best_val_acc = val_acc
            save_artifacts(config.output_dir, model, classes, config)

    print(f"Best validation accuracy: {best_val_acc:.4f}")
    print(f"Artifacts saved to: {config.output_dir}")


if __name__ == "__main__":
    main()